@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Components.Routing

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This site uses cookies to improve your experience.
    We collect only the data necessary to operate the application.
</p>

@if (HasConsent)
{
    <div class="alert alert-success mt-3">
        ✅ You have already accepted cookies. Thank you!
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        ⚠️ You have not yet accepted cookies.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    private bool HasConsent { get; set; }

    protected override void OnInitialized()
    {
        HasConsent = HttpContext.Request.Cookies.ContainsKey("consent");
    }
}

